import Expenses from './Components/Expenses/Expenses';
import NewExpense from './Components/NewExpense/NewExpense';
import React from 'react';

const dummyList = [{
  date: new Date(2021, 12, 1),
  title: "Shampoo",
  amount: 549
},
{
  date: new Date(2021, 11, 14),
  title: "Narasimha Karumanchi Algo and DS",
  amount: 345
}]
function App() {
  const [expenseList, setExpenseList] = React.useState(dummyList);

  const addExpenseHandler = (item) => {
    setExpenseList((prevState) => {
      return [...prevState, item];
    });
    console.log(item);
  }

  const deleteExpenseHandler = (toBeDeletedExpense) => {
    console.log(toBeDeletedExpense);
    setExpenseList((prevState) => {
      let tempArr = []
      for(let i = 0; i < prevState.length; i++){
        if(prevState[i] === toBeDeletedExpense)continue;
        tempArr.push(prevState[i]);
      }
      return tempArr;
    });
  }

  return (
    <div className="App">
      <NewExpense onAddExpense = {addExpenseHandler}/>
      <Expenses onDeleteExpense = {deleteExpenseHandler} expenseList = {expenseList}/>
    </div>
  );
}

export default App;
